function getCommitContent(repoPath, commitId, resource) {
 if (!commitId) {
 return null;
 }
 // klog.info(`repo:${repoPath}, commit:${commitId}, resource:${resource}`)
 const res = git.getFileContentByCommit(repoPath, commitId, resource)
 // klog.info('sssdf:' + res)
 if (res.status == 0) {
 let s = JSON.parse(res.data)["value"];
 if (s == '') {
 s = null
 }
 return s;
 }
 return null;
}

function deduplicateById(list) {
 const seen = new Set(); // 用于存储已遇到的 id
 return list.filter(item => {
 if (!item.id) return false; // 确保 item 有 id 属性
 if (seen.has(item.id)) {
 return false; // 如果 id 已存在于 Set 中，则过滤掉
 } else {
 seen.add(item.id); // 否则将 id 添加到 Set
 return true; // 保留该元素
 }
 });
}


